import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';

const MyReturns = () => {
  const [returns, setReturns] = useState([]);
  const [loading, setLoading] = useState(true);

  // Mock return data
  const mockReturns = [
    {
      id: 1,
      carName: 'Tesla Model S',
      carImage: 'https://via.placeholder.com/100x60?text=Tesla',
      bookingId: 1,
      returnDate: '2024-01-20',
      returnLocation: 'Downtown Office',
      status: 'pending',
      lateFee: 0,
      damageCharges: 0,
      totalAmount: 750,
      bookingEndDate: '2024-01-20'
    },
    {
      id: 2,
      carName: 'BMW X5',
      carImage: 'https://via.placeholder.com/100x60?text=BMW',
      bookingId: 2,
      returnDate: '2024-01-05',
      returnLocation: 'Airport Branch',
      status: 'completed',
      lateFee: 0,
      damageCharges: 0,
      totalAmount: 600,
      bookingEndDate: '2024-01-05'
    },
    {
      id: 3,
      carName: 'Mercedes C-Class',
      carImage: 'https://via.placeholder.com/100x60?text=Mercedes',
      bookingId: 3,
      returnDate: '2024-02-03',
      returnLocation: 'Downtown Office',
      status: 'scheduled',
      lateFee: 0,
      damageCharges: 0,
      totalAmount: 200,
      bookingEndDate: '2024-02-03'
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setReturns(mockReturns);
      setLoading(false);
    }, 500);
  }, []);

  const handleInitiateReturn = (returnId) => {
    alert('Return initiated! Our team will contact you shortly.');
    setReturns(returns.map(ret => 
      ret.id === returnId 
        ? { ...ret, status: 'pending' } 
        : ret
    ));
  };

  const getStatusBadge = (status) => {
    const statusClasses = {
      scheduled: 'status-pending',
      pending: 'status-active',
      completed: 'status-completed',
      late: 'status-cancelled'
    };
    return (
      <span className={`status-badge ${statusClasses[status]}`}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    );
  };

  return (
    <div style={styles.container}>
      <Navbar />
      <Sidebar />
      
      <div style={styles.dashboardContent}>
        <div style={styles.pageHeader}>
          <h1 style={styles.pageTitle}>My Returns</h1>
          <p style={styles.pageSubtitle}>Manage your car returns</p>
        </div>

        {/* Returns Info */}
        <div style={styles.infoBanner}>
          <p>💡 You can initiate a return up to 24 hours before your scheduled return date.</p>
        </div>

        {/* Returns List */}
        {loading ? (
          <div style={styles.loading}>Loading returns...</div>
        ) : returns.length === 0 ? (
          <div style={styles.emptyState}>
            <p>No returns found</p>
          </div>
        ) : (
          <div style={styles.returnsList}>
            {returns.map(returnItem => (
              <div key={returnItem.id} style={styles.returnCard}>
                <div style={styles.returnCarImage}>
                  <img 
                    src={returnItem.carImage} 
                    alt={returnItem.carName}
                    onError={(e) => {
                      e.target.src = 'https://via.placeholder.com/100x60?text=Car';
                    }}
                    style={styles.carImg}
                  />
                </div>
                
                <div style={styles.returnDetails}>
                  <h3 style={styles.carName}>{returnItem.carName}</h3>
                  <div style={styles.returnInfo}>
                    <p><strong>Booking ID:</strong> #{returnItem.bookingId}</p>
                    <p><strong>Scheduled Return:</strong> {returnItem.returnDate}</p>
                    <p><strong>Return Location:</strong> {returnItem.returnLocation}</p>
                  </div>
                </div>

                <div style={styles.returnCharges}>
                  <div style={styles.chargeItem}>
                    <span>Rental Amount:</span>
                    <span>₱{returnItem.totalAmount.toLocaleString()}</span>
                  </div>
                  <div style={styles.chargeItem}>
                    <span>Late Fee:</span>
                    <span>₱{returnItem.lateFee.toLocaleString()}</span>
                  </div>
                  <div style={styles.chargeItem}>
                    <span>Damage Charges:</span>
                    <span>₱{returnItem.damageCharges.toLocaleString()}</span>
                  </div>
                  <div style={{...styles.chargeItem, fontWeight: 'bold'}}>
                    <span>Total:</span>
                    <span>₱{(returnItem.totalAmount + returnItem.lateFee + returnItem.damageCharges).toLocaleString()}</span>
                  </div>
                </div>

                <div style={styles.returnActions}>
                  {getStatusBadge(returnItem.status)}
                  
                  {(returnItem.status === 'scheduled' || returnItem.status === 'pending') && (
                    <div style={styles.buttonGroup}>
                      <button 
                        style={styles.btnPrimary}
                        onClick={() => handleInitiateReturn(returnItem.id)}
                      >
                        {returnItem.status === 'scheduled' ? 'Initiate Return' : 'Track Return'}
                      </button>
                      <button style={styles.btnSecondary}>
                        View Details
                      </button>
                    </div>
                  )}
                  
                  {returnItem.status === 'completed' && (
                    <button style={styles.btnSecondary}>
                      Download Receipt
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #e9eefb, #f9fbfe)',
  },
  dashboardContent: {
    marginLeft: '250px',
    marginTop: '60px',
    padding: '30px',
    overflowY: 'auto',
  },
  pageHeader: {
    marginBottom: '20px',
  },
  pageTitle: {
    color: '#121253',
    fontSize: '28px',
    fontWeight: '700',
    margin: '0 0 5px 0',
  },
  pageSubtitle: {
    color: '#555',
    fontSize: '14px',
    margin: 0,
  },
  infoBanner: {
    background: '#e3f2fd',
    padding: '15px 20px',
    borderRadius: '8px',
    marginBottom: '20px',
    borderLeft: '4px solid #2196f3',
  },
  loading: {
    textAlign: 'center',
    padding: '40px',
    color: '#555',
  },
  emptyState: {
    textAlign: 'center',
    padding: '40px',
    color: '#555',
    background: 'white',
    borderRadius: '8px',
  },
  returnsList: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  returnCard: {
    background: 'white',
    padding: '20px',
    borderRadius: '8px',
    boxShadow: '0 5px 15px rgb(56 56 92 / 0.1)',
    display: 'flex',
    gap: '20px',
    flexWrap: 'wrap',
    alignItems: 'center',
  },
  returnCarImage: {
    flex: '0 0 100px',
  },
  carImg: {
    width: '100px',
    height: '60px',
    objectFit: 'cover',
    borderRadius: '6px',
  },
  returnDetails: {
    flex: '1',
    minWidth: '200px',
  },
  carName: {
    color: '#121253',
    margin: '0 0 10px 0',
    fontSize: '18px',
  },
  returnInfo: {
    fontSize: '14px',
    color: '#555',
  },
  returnCharges: {
    flex: '0 0 200px',
    padding: '15px',
    background: '#f8f9fa',
    borderRadius: '6px',
  },
  chargeItem: {
    display: 'flex',
    justifyContent: 'space-between',
    fontSize: '14px',
    marginBottom: '8px',
    color: '#555',
  },
  returnActions: {
    flex: '0 0 200px',
    display: 'flex',
    flexDirection: 'column',
    gap: '10px',
    alignItems: 'flex-start',
  },
  buttonGroup: {
    display: 'flex',
    gap: '10px',
    flexWrap: 'wrap',
  },
  btnPrimary: {
    background: '#3f42c7',
    border: 'none',
    color: 'white',
    padding: '10px 20px',
    borderRadius: '6px',
    fontWeight: '600',
    cursor: 'pointer',
  },
  btnSecondary: {
    background: '#6c757d',
    border: 'none',
    color: 'white',
    padding: '10px 20px',
    borderRadius: '6px',
    fontWeight: '600',
    cursor: 'pointer',
  },
};

export default MyReturns;
